import React from 'react';

const s = {
  nav: {
    background: '#fff',
    borderBottom: '1px solid #e5e7eb',
    position: 'sticky',
    top: 0,
    zIndex: 100,
    boxShadow: '0 1px 3px rgba(0,0,0,0.07)',
  },
  container: {
    maxWidth: 1280,
    margin: '0 auto',
    padding: '0 24px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'space-between',
    height: 64,
  },
  logo: {
    fontSize: 20,
    fontWeight: 700,
    color: '#2563eb',
    display: 'flex',
    alignItems: 'center',
    gap: 8,
  },
  menu: {
    display: 'flex',
    gap: 0,
    listStyle: 'none',
    margin: 0,
    padding: 0,
  },
  menuItem: (active) => ({
    padding: '8px 16px',
    cursor: 'pointer',
    fontWeight: 500,
    fontSize: 13,
    color: active ? '#2563eb' : '#6b7280',
    borderBottom: active ? '3px solid #2563eb' : '3px solid transparent',
    transition: 'all 0.2s',
    marginBottom: -3,
  }),
};

export default function Navigation({ currentPage, onPageChange }) {
  const pages = [
    { key: 'about', label: 'ℹ️ About', icon: 'ℹ️' },
    { key: 'candidate', label: '👤 Candidate', icon: '👤' },
    { key: 'recruiter', label: '🔍 Recruiter', icon: '🔍' },
    { key: 'companies', label: '🏢 Companies', icon: '🏢' },
  ];

  return (
    <nav style={s.nav}>
      <div style={s.container}>
        <div style={s.logo}>
          🎯 HireSense
        </div>
        <ul style={s.menu}>
          {pages.map(page => (
            <li key={page.key}>
              <div
                style={s.menuItem(currentPage === page.key)}
                onClick={() => onPageChange(page.key)}
              >
                {page.label}
              </div>
            </li>
          ))}
        </ul>
      </div>
    </nav>
  );
}
